INSERT INTO destinations (destination_id, name, description, image_url, backdrop_url, region, country, district, address, category, tags, best_time_to_visit, travel_style, budget_level, budget_range, trip_duration, recommended_duration, best_season, avg_cost_per_day, monthly_visitors, rating, popularity, latitude, longitude, highlights) VALUES
('dest-001', 'Araku Valley', 'A lush hill station framed by coffee estates, waterfalls, and misty valleys.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Alluri Sitharama Raju', 'Araku Valley, Andhra Pradesh', 'Hill Station', 'Hill Station, Coffee, Nature', 'Winter', 'Hill Station', 'Medium', 'Medium', 3, 3, 'Winter', 3500, 85000, 4.8, 95, 18.3274, 82.8806, 'Coffee plantation views, tribal craft markets, and scenic train rides.'),
('dest-002', 'Borra Caves', 'One of Asia''s deepest caves with glittering stalactites and ancient limestone formations.', 'https://images.unsplash.com/photo-1511739001486-6bfe10ce785f?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1511739001486-6bfe10ce785f?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Alluri Sitharama Raju', 'Borra Caves Road, Andhra Pradesh', 'Nature Tourism', 'Nature, Caves, Adventure', 'Winter', 'Nature Tourism', 'Medium', 'Medium', 1, 1, 'Winter', 2800, 76000, 4.7, 88, 18.3520, 82.7871, 'Guided cave tours, underground rivers, and dramatic lighting effects.'),
('dest-003', 'Lambasingi', 'A cold-climate village known as the "Kashmir of Andhra Pradesh" and misty pine forests.', 'https://images.unsplash.com/photo-1519817650390-64a93db5118a?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1519817650390-64a93db5118a?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Alluri Sitharama Raju', 'Lambasingi, Andhra Pradesh', 'Adventure Tourism', 'Adventure, Nature, Trekking', 'Winter', 'Adventure Tourism', 'Budget', 'Budget', 2, 2, 'Winter', 2200, 53000, 4.5, 78, 18.3500, 82.5766, 'Foggy mornings, trekking, and camping under silver oak woodlands.'),
('dest-004', 'RK Beach', 'A wide urban beach with sunrise views, a marine aquarium, and active promenades.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Visakhapatnam', 'Ramakrishna Beach Road, Visakhapatnam', 'Beach Tourism', 'Beach, Sunrise, Urban', 'Summer', 'Beach Tourism', 'Budget', 'Budget', 1, 1, 'Summer', 2400, 98000, 4.4, 92, 17.7239, 83.3270, 'Seaside cafes, thousand-year-old lighthouse, and evening strolls by the Bay of Bengal.'),
('dest-005', 'Simhachalam Temple', 'Ancient hill shrine dedicated to Lord Narasimha with dramatic Dravidian architecture.', 'https://images.unsplash.com/photo-1529960536864-0d4ea1d7fbdd?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1529960536864-0d4ea1d7fbdd?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Visakhapatnam', 'Simhachalam, Visakhapatnam', 'Temple Tourism', 'Temple, Heritage, Pilgrimage', 'All Seasons', 'Temple Tourism', 'Medium', 'Medium', 1, 1, 'All Seasons', 2600, 72000, 4.6, 81, 17.8044, 83.3416, 'Sacred rituals, stone carvings, and a serene hilltop atmosphere.'),
('dest-006', 'Tirumala Temple', 'World-famous Vaishnavite shrine attracting millions of pilgrims each year.', 'https://images.unsplash.com/photo-1513635269975-59663e0ac1ad?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1513635269975-59663e0ac1ad?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Tirupati', 'Tirumala, Tirupati', 'Temple Tourism', 'Pilgrimage, Spiritual, Heritage', 'All Seasons', 'Temple Tourism', 'Medium', 'Medium', 1, 1, 'All Seasons', 3000, 120000, 4.9, 100, 13.6831, 79.3470, 'Spiritual processions, sacred hills, and legendary temple cuisine.'),
('dest-007', 'Srikalahasti Temple', 'Historic temple famed for Vayu stalam and sculpted gopurams by the Swarnamukhi river.', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Tirupati', 'Srikalahasti, Andhra Pradesh', 'Temple Tourism', 'Temple, Heritage, Spiritual', 'All Seasons', 'Temple Tourism', 'Medium', 'Medium', 1, 1, 'All Seasons', 2800, 64000, 4.7, 79, 13.7500, 79.7000, 'Stone mythology, evening aarti, and spiritual heritage.'),
('dest-008', 'Horsley Hills', 'Rolling hills and dense forests offering a cool retreat and easy hikes.', 'https://images.unsplash.com/photo-1519817650390-64a93db5118a?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1519817650390-64a93db5118a?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Tirupati', 'Horsley Hills, Andhra Pradesh', 'Hill Station', 'Hill Station, Nature, Retreat', 'Winter', 'Hill Station', 'Medium', 'Medium', 2, 2, 'Winter', 3200, 47000, 4.5, 76, 13.2690, 78.5084, 'Panoramic viewpoints, apple orchards, and winding hill roads.'),
('dest-009', 'Belum Caves', 'Vast limestone caves with dramatic stalactites, underground lakes, and rare formations.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Nandyal', 'Belum Caves, Andhra Pradesh', 'Nature Tourism', 'Caves, Heritage, Adventure', 'Winter', 'Nature Tourism', 'Budget', 'Budget', 1, 1, 'Winter', 2100, 38000, 4.6, 72, 15.8285, 78.4410, 'Cavern tours, silent chambers, and a hidden natural wonder.'),
('dest-010', 'Gandikota', 'A dramatic gorge along the Penna river often called the ''Grand Canyon of India''.', 'https://images.unsplash.com/photo-1545060894-4f79a9d559db?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1545060894-4f79a9d559db?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Kadapa', 'Gandikota, Andhra Pradesh', 'Historical Sites', 'Heritage, Gorge, Adventure', 'Winter', 'Historical Sites', 'Budget', 'Budget', 1, 1, 'Winter', 2000, 55000, 4.5, 84, 14.6907, 78.3203, 'Ruin exploration, fort walls, and sunset views over the gorge.'),
('dest-011', 'Lepakshi Temple', 'A historic Veerabhadra temple with carved pillars, monolithic Nandi, and frescoes.', 'https://images.unsplash.com/photo-1521434469754-780fffd37d05?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1521434469754-780fffd37d05?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Anantapur', 'Lepakshi, Andhra Pradesh', 'Temple Tourism', 'Temple, Heritage, Art', 'Winter', 'Temple Tourism', 'Budget', 'Budget', 1, 1, 'Winter', 1800, 67000, 4.8, 70, 13.7500, 77.7138, 'Intricate stone carving, dancing pillars, and cultural legend.'),
('dest-012', 'Ahobilam', 'A mystical temple complex nestled in the Nallamala Hills with ancient Narasimha shrines.', 'https://images.unsplash.com/photo-1493559879380-2d5f3f44f9fb?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1493559879380-2d5f3f44f9fb?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Nandyal', 'Ahobilam, Andhra Pradesh', 'Temple Tourism', 'Temple, Hills, Spiritual', 'All Seasons', 'Temple Tourism', 'Medium', 'Medium', 2, 2, 'All Seasons', 2400, 45000, 4.7, 68, 15.2500, 78.9000, 'Hill temples, river views, and serene pilgrimage trails.'),
('dest-013', 'Amaravati', 'The ancient Buddhist capital known for its stupa ruins and museum collections.', 'https://images.unsplash.com/photo-1504384308090-c894fdcc538d?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1504384308090-c894fdcc538d?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Guntur', 'Amaravati, Andhra Pradesh', 'Historical Sites', 'Buddhist, Heritage, Culture', 'All Seasons', 'Historical Sites', 'Medium', 'Medium', 1, 1, 'All Seasons', 2600, 72000, 4.4, 73, 16.5417, 80.5150, 'Buddhist heritage, archaeological sites, and riverside gardens.'),
('dest-014', 'Kondapalli Fort', 'A hill fortress with sweeping views, ancient gateways, and toy-making craftsmanship.', 'https://images.unsplash.com/photo-1526772662000-3f88f10405ff?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1526772662000-3f88f10405ff?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Krishna', 'Kondapalli, Andhra Pradesh', 'Historical Sites', 'Heritage, Fort, Craft', 'Winter', 'Historical Sites', 'Budget', 'Budget', 1, 1, 'Winter', 2100, 33000, 4.3, 62, 16.5394, 80.8727, 'Fort walls, traditional toys, and local village markets.'),
('dest-015', 'Bhavani Island', 'A tranquil island in the Godavari River offering river safaris and green landscapes.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Kakinada', 'Bhavani Island, Andhra Pradesh', 'Nature Tourism', 'Island, River, Relaxation', 'Winter', 'Nature Tourism', 'Medium', 'Medium', 1, 1, 'Winter', 2500, 62000, 4.6, 66, 16.9961, 82.2560, 'Boat rides, mangrove views, and weekend picnics.'),
('dest-016', 'Mypadu Beach', 'A white sand beach with calm waters popular for weekend escapes and seafood.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Nellore', 'Mypadu Beach, Andhra Pradesh', 'Beach Tourism', 'Beach, Relaxation, Seafood', 'Summer', 'Beach Tourism', 'Budget', 'Budget', 2, 2, 'Summer', 2300, 47000, 4.4, 64, 14.3375, 80.0017, 'Water sports, beachside restaurants, and long sunset walks.'),
('dest-017', 'Pulicat Lake', 'A scenic coastal lagoon famous for migratory birds, fishing villages, and backwater cruises.', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Nellore', 'Pulicat Lake, Andhra Pradesh', 'Nature Tourism', 'Birding, Lagoon, Wildlife', 'Winter', 'Nature Tourism', 'Medium', 'Medium', 1, 1, 'Winter', 2600, 54000, 4.5, 61, 13.5850, 80.0500, 'Bird watching, lagoon cruises, and salt marsh landscapes.'),
('dest-018', 'Coringa Wildlife Sanctuary', 'A mangrove sanctuary home to rare birds, estuarine ecosystems, and conservation trails.', 'https://images.unsplash.com/photo-1493559879380-2d5f3f44f9fb?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1493559879380-2d5f3f44f9fb?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Kakinada', 'Coringa Wildlife Sanctuary, Andhra Pradesh', 'Nature Tourism', 'Wildlife, Mangrove, Ecology', 'Winter', 'Nature Tourism', 'Medium', 'Medium', 1, 1, 'Winter', 2700, 39000, 4.5, 60, 16.9037, 82.1870, 'Mangrove boardwalks, bird hides, and river delta ecology.'),
('dest-019', 'Kakinada Beach', 'A popular coastal stretch with iconic colonial pier views and sunrise ambience.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Kakinada', 'Kakinada Beach Road, Andhra Pradesh', 'Beach Tourism', 'Beach, Sunrise, Local', 'Summer', 'Beach Tourism', 'Budget', 'Budget', 1, 1, 'Summer', 2200, 59000, 4.4, 67, 16.9580, 82.2383, 'Beach walks, local seafood stalls, and sunset photography.'),
('dest-020', 'Rollapadu Wildlife Sanctuary', 'A dry deciduous reserve known for blackbuck, migratory birds, and open plains.', 'https://images.unsplash.com/photo-1493559879380-2d5f3f44f9fb?auto=format&fit=crop&w=1200&q=80', 'https://images.unsplash.com/photo-1493559879380-2d5f3f44f9fb?auto=format&fit=crop&w=1200&q=80', 'Andhra Pradesh', 'India', 'Nandyal', 'Rollapadu, Andhra Pradesh', 'Nature Tourism', 'Wildlife, Safari, Birding', 'Winter', 'Nature Tourism', 'Budget', 'Budget', 2, 2, 'Winter', 2100, 30000, 4.3, 58, 15.7139, 78.1203, 'Wildlife safaris, birding trails, and rural landscape photography.');
